<script>
(function(){
    var rawText=document.getElementById('rawText').textContent.trim();
    var leftText=rawText;
    var rightText='';
    var idx=rawText.indexOf('[OS]');

    if(idx!==-1){
        leftText=rawText.substring(0,idx).trim();
        rightText=rawText.substring(idx+4).trim();
    }

    document.getElementById('leftDisplay').textContent=leftText;
    document.getElementById('rightDisplay').textContent=rightText;

    var body=document.body;
    var leftCard=document.getElementById('leftCard');
    var leftHeader=document.getElementById('leftHeader');
    var leftExpanded=false;

    var rightCard=document.getElementById('rightCard');
    var rightHeader=document.getElementById('rightHeader');
    var rightExpanded=false;

    var themeToggleBtn=document.getElementById('themeToggleBtn');

    function toggleCard(card,header,getExp,setExp){
        return function(e){
            if(e)e.stopPropagation();
            if(getExp()){
                card.classList.remove('expanded');
                setExp(false);
                header.setAttribute('aria-expanded','false');
            }else{
                card.classList.add('expanded');
                setExp(true);
                header.setAttribute('aria-expanded','true');
            }
        };
    }

    leftHeader.addEventListener('click',toggleCard(leftCard,leftHeader,function(){return leftExpanded},function(v){leftExpanded=v}));
    rightHeader.addEventListener('click',toggleCard(rightCard,rightHeader,function(){return rightExpanded},function(v){rightExpanded=v}));

    leftHeader.addEventListener('keydown',function(e){
        if(e.key==='Enter'||e.key===' '){
            e.preventDefault();
            leftHeader.click();
        }
    });

    rightHeader.addEventListener('keydown',function(e){
        if(e.key==='Enter'||e.key===' '){
            e.preventDefault();
            rightHeader.click();
        }
    });

    function applyTheme(t){
        if(t==='light'){
            body.classList.add('light-theme');
            body.classList.remove('dark-theme');
            try{localStorage.setItem('fox-preset-theme','light')}catch(e){}
        }else{
            body.classList.remove('light-theme');
            body.classList.add('dark-theme');
            try{localStorage.setItem('fox-preset-theme','dark')}catch(e){}
        }
    }

    var st=null;
    try{st=localStorage.getItem('fox-preset-theme')}catch(e){}

    if(st==='light'||st==='day')applyTheme('light');
    else if(st==='dark'||st==='night')applyTheme('dark');
    else applyTheme('dark');

    themeToggleBtn.addEventListener('click',function(e){
        e.stopPropagation();
        if(body.classList.contains('light-theme'))applyTheme('dark');
        else applyTheme('light');
    });

    function rr(a,b){return a+Math.random()*(b-a)}

    function spawnParticles(container){
        var isMob=window.innerWidth<720;
        var dots=isMob?8:15;
        var lines=isMob?0:5;

        for(var i=0;i<dots;i++){
            var dot=document.createElement('div');
            dot.className='ax-p particle-dot';
            var size=rr(1.5,4);
            dot.style.width=size+'px';
            dot.style.height=size+'px';
            dot.style.left=rr(5,90)+'%';
            dot.style.top=rr(10,85)+'%';
            dot.style.setProperty('--pdur',rr(6,14)+'s');
            dot.style.setProperty('--pdel',-(Math.random()*14)+'s');
            dot.style.setProperty('--pdx',rr(-6,6)+'px');
            dot.style.setProperty('--popeak',rr(.25,.55).toFixed(2));
            container.appendChild(dot);
        }

        for(var j=0;j<lines;j++){
            var line=document.createElement('div');
            line.className='ax-p particle-line';
            line.style.height=rr(20,60)+'px';
            line.style.left=rr(8,88)+'%';
            line.style.top=rr(10,80)+'%';
            line.style.setProperty('--pdur',rr(8,16)+'s');
            line.style.setProperty('--pdel',-(Math.random()*16)+'s');
            line.style.setProperty('--popeak',rr(.2,.45).toFixed(2));
            container.appendChild(line);
        }
    }

    spawnParticles(document.getElementById('leftParticles'));
    spawnParticles(document.getElementById('rightParticles'));

    leftHeader.setAttribute('aria-expanded','false');
    rightHeader.setAttribute('aria-expanded','false');
})();
</script>
</body>
