@keyframes particleLine{0%,100%{transform:scaleY(.2);opacity:0}15%{opacity:var(--popeak,.4)}45%{transform:scaleY(1);opacity:var(--popeak,.4)}70%{transform:scaleY(.6);opacity:calc(var(--popeak,.4)*.2)}95%{opacity:0}}
