(function(){
    var rawText=document.getElementById('rawText').textContent.trim();
    var leftText=rawText,rightText='',idx=rawText.indexOf('[OS]');
    if(idx!==-1){
        leftText=rawText.substring(0,idx).trim();
        rightText=rawText.substring(idx+4).trim();
    }
    document.getElementById('leftDisplay').textContent=leftText;
    document.getElementById('rightDisplay').textContent=rightText;

    var body=document.body;
    var leftCard=document.getElementById('leftCard'),leftHeader=document.getElementById('leftHeader'),leftExpanded=false;
    var rightCard=document.getElementById('rightCard'),rightHeader=document.getElementById('rightHeader'),rightExpanded=false;
    var themeToggleBtn=document.getElementById('themeToggleBtn');

    function toggleCard(card,header,isExp,setExp){
        return function(e){
            if(e)e.stopPropagation();
            if(isExp()){
                card.classList.remove('expanded');
                setExp(false);
                header.setAttribute('aria-expanded','false');
            }else{
                card.classList.add('expanded');
                setExp(true);
                header.setAttribute('aria-expanded','true');
            }
        }
    }

    leftHeader.addEventListener('click',toggleCard(leftCard,leftHeader,function(){return leftExpanded},function(v){leftExpanded=v}));
    rightHeader.addEventListener('click',toggleCard(rightCard,rightHeader,function(){return rightExpanded},function(v){rightExpanded=v}));

    leftHeader.addEventListener('keydown',function(e){
        if(e.key==='Enter'||e.key===' '){e.preventDefault();leftHeader.click();}
    });
    rightHeader.addEventListener('keydown',function(e){
        if(e.key==='Enter'||e.key===' '){e.preventDefault();rightHeader.click();}
    });

    function applyTheme(t){
        if(t==='light'){
            body.classList.add('light-theme');
            body.classList.remove('dark-theme');
            try{localStorage.setItem('fox-preset-theme','light')}catch(e){}
        }else{
            body.classList.remove('light-theme');
            body.classList.add('dark-theme');
            try{localStorage.setItem('fox-preset-theme','dark')}catch(e){}
        }
    }

    var st=null;
    try{st=localStorage.getItem('fox-preset-theme')}catch(e){}
    if(st==='light'||st==='day')applyTheme('light');
    else if(st==='dark'||st==='night')applyTheme('dark');
    else applyTheme('dark');

    themeToggleBtn.addEventListener('click',function(e){
        e.stopPropagation();
        if(body.classList.contains('light-theme'))applyTheme('dark');
        else applyTheme('light');
    });
})();
</script>
</body>
