    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'PingFang SC', 'Microsoft YaHei', 'Inter', 'Helvetica Neue', 'Noto Sans', sans-serif;
    background: transparent;
    line-height: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: color 0.35s ease;
}

.rim-collapsible {
    width: 100%;
    max-width: 540px;
    margin: 0 auto;
    background: var(--bg-base);
    border-radius: 17px;
    border: 1px solid var(--border-main);
    overflow: hidden;
    box-shadow: var(--shadow-outer), var(--shadow-inner);
    transition: border-color 0.35s ease, box-shadow 0.35s ease, background 0.35s ease;
    position: relative;
    contain: layout;
}

.rim-collapsible::before {
    content: '';
    position: absolute;
    pointer-events: none;
    z-index: 0;
    inset: -50%;
    background: var(--panel-aura-bg);
    opacity: var(--panel-aura-opacity);
    animation: foxAura 8s ease-in-out infinite;
    transition: opacity 0.35s ease, background 0.35s ease;
    border-radius: 50%;
}

body.night-mode .rim-collapsible::before {
    inset: 0;
    border-radius: 0;
    animation: none;
    transform: translateX(-25%);
}

.rim-collapsible::after {
    content: '';
    position: absolute;
    pointer-events: none;
    z-index: 0;
    left: 18px;
    right: 18px;
    top: 0;
    height: 1px;
    background: var(--panel-top-line);
    opacity: var(--panel-top-line-opacity);
    transition: opacity 0.35s ease, background 0.35s ease;
}

.rim-collapsible:hover {
    box-shadow: var(--shadow-hover), var(--shadow-inner);
}

@keyframes foxAura {
    0%, 100% {
        transform: translate(-4%, -2%) scale(1);
        opacity: 0.45;
    }
    50% {
        transform: translate(4%, 3%) scale(1.08);
        opacity: 0.75;
    }
}

.rim-header {
    position: relative;
    padding: 13px 17px 10px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
    border-bottom: 1px dashed var(--border-dash);
    transition: background 0.3s ease, border-color 0.35s ease;
    outline: none;
    -webkit-tap-highlight-color: transparent;
    z-index: 2;
}

body.night-mode .rim-header {
    border-bottom: 1px solid var(--border-dash);
}

.rim-header:hover {
    background: var(--bg-header-hover);
}

.rim-header:focus-visible {
    box-shadow: inset 0 0 0 1.5px var(--border-main);
    border-radius: 17px 17px 0 0;
}

.rim-title {
    display: flex;
    align-items: center;
    gap: 10px;
    font-size: 16px;
    font-weight: 850;
    color: var(--text-primary);
    letter-spacing: 0.06em;
    white-space: nowrap;
    transition: color 0.35s ease, text-shadow 0.35s ease;
    text-shadow: var(--title-text-shadow);
    min-width: 0;
}

.rim-status-dot {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    background: var(--icon-bg);
    border: 1px solid var(--icon-border);
    box-shadow: var(--icon-shadow);
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 15px;
    color: var(--icon-color);
    transition: background 0.35s ease, color 0.35s ease, border-color 0.35s ease, box-shadow 0.35s ease;
}

.header-actions {
    display: flex;
    align-items: center;
    gap: 8px;
    z-index: 2;
    flex-shrink: 0;
}

.mode-toggle-btn,
.append-toggle-btn,
.theme-toggle-btn {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    border: 1px solid var(--btn-border);
    background: var(--btn-bg);
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    transition: background 0.35s ease, border-color 0.35s ease, transform 0.2s ease, box-shadow 0.35s ease, color 0.35s ease;
    line-height: 1;
    padding: 0;
    outline: none;
    -webkit-tap-highlight-color: transparent;
    position: relative;
    z-index: 3;
    user-select: none;
    box-shadow: var(--btn-shadow);
    color: var(--btn-color);
}

.mode-toggle-btn { font-size: 12px; }
.append-toggle-btn { font-size: 13px; }
.theme-toggle-btn { font-size: 13px; }

.mode-toggle-btn:hover,
.append-toggle-btn:hover,
.theme-toggle-btn:hover {
    transform: var(--btn-hover-transform);
    box-shadow: 0 6px 12px rgba(170, 90, 35, 0.12), inset 0 1px 0 rgba(255, 255, 255, 0.74);
}

body.night-mode .mode-toggle-btn:hover,
body.night-mode .append-toggle-btn:hover,
body.night-mode .theme-toggle-btn:hover {
    box-shadow: 0 6px 12px rgba(0, 0, 0, 0.26), inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.mode-toggle-btn:active,
.append-toggle-btn:active,
.theme-toggle-btn:active {
    transform: var(--btn-active-transform);
    transition: transform 0.1s ease;
}

.mode-toggle-btn:focus-visible,
.append-toggle-btn:focus-visible,
.theme-toggle-btn:focus-visible {
    box-shadow: 0 0 0 1.5px var(--border-main);
}

.mode-toggle-btn.send-mode {
    border-color: var(--send-mode-border);
    box-shadow: var(--send-mode-glow), var(--btn-shadow);
}

.append-toggle-btn.append-mode {
    border-color: var(--send-mode-border);
    box-shadow: var(--send-mode-glow), var(--btn-shadow);
}

.toggle-icon {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    background: var(--toggle-bg);
    display: flex;
    align-items: center;
    justify-content: center;
    transition: transform 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275), background 0.35s ease;
    box-shadow: var(--btn-shadow);
    position: relative;
    z-index: 2;
    border: 1px solid var(--btn-border);
}

.toggle-icon::before {
    content: '+';
    color: var(--toggle-symbol-color);
    font-size: 18px;
    font-weight: 700;
    line-height: 1;
    transition: transform 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

.rim-collapsible.expanded .toggle-icon {
    transform: scale(1.06) rotate(360deg);
}

.rim-collapsible.expanded .toggle-icon::before {
    transform: rotate(135deg);
}

.rim-content {
    display: block;
    max-height: 0;
    overflow: hidden;
    background: var(--bg-content);
    position: relative;
    z-index: 2;
    opacity: 0;
    transform: translateY(-4px);
    transition:
        max-height 0.42s cubic-bezier(0.4, 0, 0.2, 1),
        opacity 0.26s ease,
        transform 0.3s cubic-bezier(0.18, 0.89, 0.32, 1.12),
        background 0.35s ease;
    will-change: auto;
}

.rim-collapsible.expanded .rim-content {
    opacity: 1;
    transform: translateY(0);
}

.rim-content-shell {
    min-height: 0;
    overflow: visible;
}

.fox-tip-area {
    position: relative;
    z-index: 2;
    margin: 10px 17px 0;
    padding: 9px 12px;
    border-radius: 10px;
    font-size: 12px;
    line-height: 1.55;
    color: var(--tip-color);
    background: var(--tip-bg);
    border: 1px solid var(--tip-border);
    transition: all 0.35s ease;
    letter-spacing: 0.03em;
    font-style: italic;
}

.fox-tip-area::before {
    content: '🦊';
    margin-right: 6px;
    font-style: normal;
}

.fox-tip-area:empty {
    display: none;
}

.rim-content-inner {
    position: relative;
    z-index: 2;
    display: flex;
    flex-direction: column;
    gap: 8px;
    padding: 13px 17px 10px;
}

.action-card {
    position: relative;
    overflow: hidden;
    display: flex;
    align-items: center;
    gap: 10px;
    width: 100%;
    min-height: 44px;
    padding: 10px 14px;
    text-align: left;
    background: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 10px;
    color: var(--text-card);
    font-size: 13px;
    font-weight: 580;
    letter-spacing: 0.03em;
    cursor: pointer;
    transition:
        transform 0.22s cubic-bezier(0.18, 0.89, 0.32, 1.16),
        box-shadow 0.22s ease,
        border-color 0.22s ease,
        background 0.22s ease,
        color 0.22s ease;
    box-shadow: var(--shadow-card);
    line-height: 1.5;
    user-select: none;
    -webkit-tap-highlight-color: transparent;
    z-index: 2;
    white-space: pre-wrap;
    word-break: break-word;
    overflow-wrap: anywhere;
}

.action-card:hover {
    border-color: var(--border-card-hover);
    background: var(--bg-card-hover);
    box-shadow: var(--shadow-card-hover);
    transform: translateX(2px);
}

.action-card:active {
    transform: translateY(1px);
    background: var(--card-active-bg);
    border-color: var(--card-active-border);
    box-shadow: inset 0 1px 4px rgba(0, 0, 0, 0.15);
    transition: 0.06s;
}

.action-card::after {
    content: '';
    position: absolute;
    inset: 0;
    transform: translateX(-130%);
    opacity: 0;
    pointer-events: none;
    background: linear-gradient(120deg, transparent, var(--card-sweep-color), transparent);
    border-radius: 10px;
}

.action-card:hover::after {
    animation: foxSweep 0.72s ease;
}

@keyframes foxSweep {
    0% {
        transform: translateX(-130%);
        opacity: 0;
    }
    35% {
        opacity: 0.65;
    }
    100% {
        transform: translateX(130%);
        opacity: 0;
    }
}

.action-card.just-used {
    border-color: var(--card-active-border);
    background: var(--card-active-bg);
    box-shadow: 0 8px 18px rgba(170, 90, 35, 0.14), inset 0 1px 0 rgba(255, 255, 255, 0.88);
    transition: 0.12s;
}

body.night-mode .action-card.just-used {
    box-shadow: 0 8px 18px rgba(0, 0, 0, 0.28), inset 0 1px 0 rgba(255, 255, 255, 0.05);
}

.no-options-hint {
    text-align: center;
    color: var(--text-footer);
    opacity: 0.6;
    font-size: 12px;
    padding: 8px;
    width: 100%;
}

.rim-footer-toggle {
    display: block;
    text-align: center;
    padding: 12px 0 14px;
    color: var(--text-footer);
    opacity: 0.70;
    font-size: 13px;
    font-weight: 500;
    cursor: pointer;
    transition: transform 0.2s ease, opacity 0.2s ease, color 0.35s ease;
    user-select: none;
    letter-spacing: 0.03em;
    border-top: 1px dashed var(--border-dash);
    margin-top: 2px;
    position: relative;
    z-index: 2;
}

.rim-footer-toggle:hover {
    opacity: 1;
    transform: scale(var(--footer-hover-scale));
}

.rim-footer-toggle:active {
    transform: scale(0.97);
    transition: transform 0.08s ease;
}

.status-feedback {
    position: relative;
    z-index: 2;
    margin: -4px 17px 15px;
    padding: 8px 10px;
    border-radius: 9px;
    font-size: 12px;
    line-height: 1.5;
    color: var(--tip-color);
    background: rgba(255, 238, 210, 0.34);
    border: 1px dashed rgba(220, 160, 95, 0.26);
    letter-spacing: 0.03em;
    font-weight: 450;
    transition: background 0.35s ease, color 0.35s ease, border-color 0.35s ease, opacity 0.25s ease;
}

body.night-mode .status-feedback {
    color: #888;
    background: rgba(255, 255, 255, 0.026);
    border: 1px dashed rgba(255, 255, 255, 0.055);
}

@media (max-width: 480px) {
    .rim-collapsible {
        border-radius: 15px;
    }

    .rim-header {
        padding: 12px 14px 9px;
    }

    .rim-title {
        font-size: 15px;
    }

    .rim-content-inner {
        gap: 6px;
        padding: 12px 14px 10px;
    }

    .action-card {
        font-size: 12.5px;
        padding: 9px 12px;
        min-height: 40px;
    }

    .fox-tip-area {
        margin: 9px 14px 0;
        padding: 8px 10px;
        font-size: 11px;
    }

    .status-feedback {
        margin: -4px 14px 14px;
    }

    .rim-collapsible::before {
        animation-duration: 12s;
        opacity: 0.55;
    }
}

@media (prefers-reduced-motion: reduce) {
    .rim-collapsible::before,
    .action-card:hover::after {
        animation: none !important;
    }

    .action-card,
    .mode-toggle-btn,
    .append-toggle-btn,
    .theme-toggle-btn,
    .toggle-icon,
    .rim-collapsible,
    .rim-header,
    .fox-tip-area,
    .status-feedback,
    .rim-content {
        transition-duration: 0.12s !important;
    }
}
</style>
</head>

<body>
<div class="rim-collapsible" id="rimCollapsible">
    <div class="rim-header" onclick="toggleCollapsible()" tabindex="0" role="button" aria-expanded="false">
        <div class="rim-title">
            <span class="rim-status-dot">🦊</span>
            狐策~
        </div>
        <div class="header-actions">
            <button class="mode-toggle-btn" id="modeToggleBtn" onclick="toggleMode(event)" title="填充模式（点击切换为发送）" aria-label="切换输入模式">↓</button>
            <button class="append-toggle-btn" id="appendToggleBtn" onclick="toggleAppendMode(event)" title="追加模式：关闭" aria-label="切换追加模式">↵</button>
            <button class="theme-toggle-btn" id="themeToggleBtn" onclick="toggleTheme(event)" title="切换日夜模式" aria-label="切换日夜模式">✦</button>
            <div class="toggle-icon"></div>
        </div>
    </div>

    <div class="rim-content">
        <div class="rim-content-shell">
            <div class="fox-tip-area" id="foxTipArea"></div>
            <div class="rim-content-inner" id="actionsContainer"></div>
            <div class="rim-footer-toggle">— 点击收起 —</div>
            <div class="status-feedback" id="statusFeedback">待命</div>
        </div>
    </div>
</div>

<script>
(function() {
    const DEFAULT_OPTIONS = ["扫描区域", "建造掩体", "紧急医疗"];

    const ACTION_THEME_STORAGE_KEY = 'fox-action-options-theme';
    const APPEND_MODE_STORAGE_KEY = 'fox-action-append-mode';

    const collapsible = document.getElementById('rimCollapsible');
    const content = collapsible.querySelector('.rim-content');
    const actionsContainer = document.getElementById('actionsContainer');
    const foxTipArea = document.getElementById('foxTipArea');
    const themeToggleBtn = document.getElementById('themeToggleBtn');
    const statusFeedback = document.getElementById('statusFeedback');

    let isExpanded = false;
    let isSendMode = false;
    let isAppendMode = false;

    const safeTriggerSlash = (typeof triggerSlash === 'function') ? triggerSlash : (cmd) => {
        console.warn('[环世界面板] triggerSlash 未定义，模拟执行:', cmd);
        if (statusFeedback) {
            statusFeedback.textContent = `模拟: ${cmd.substring(0, 30)}`;
        }
    };

    function applyActionTheme(theme) {
        if (theme === 'dark' || theme === 'night') {
            document.body.classList.add('night-mode');
            if (themeToggleBtn) themeToggleBtn.textContent = '✧';
        } else {
            document.body.classList.remove('night-mode');
            if (themeToggleBtn) themeToggleBtn.textContent = '✦';
        }
    }

    function loadActionTheme() {
        let savedTheme = null;
        try {
            savedTheme = localStorage.getItem(ACTION_THEME_STORAGE_KEY);
        } catch (e) {}

        if (savedTheme === 'dark' || savedTheme === 'night') {
            applyActionTheme('dark');
        } else {
            applyActionTheme('light');
        }
    }

    function loadAppendMode() {
        let savedAppendMode = null;
        try {
            savedAppendMode = localStorage.getItem(APPEND_MODE_STORAGE_KEY);
        } catch (e) {}

        if (savedAppendMode === 'true') {
            isAppendMode = true;
            updateAppendModeUI();
        } else {
            isAppendMode = false;
            updateAppendModeUI();
        }
    }

    function updateAppendModeUI() {
        const appendBtn = document.getElementById('appendToggleBtn');
        const modeBtn = document.getElementById('modeToggleBtn');

        if (isAppendMode) {
            isSendMode = false;

            if (modeBtn) {
                modeBtn.textContent = '↓';
                modeBtn.title = '填充模式（点击切换为发送）';
                modeBtn.classList.remove('send-mode');
            }

            if (appendBtn) {
                appendBtn.textContent = '▸⏎';
                appendBtn.title = '追加模式：开启';
                appendBtn.classList.add('append-mode');
            }
        } else {
            if (appendBtn) {
                appendBtn.textContent = '↵';
                appendBtn.title = '追加模式：关闭';
                appendBtn.classList.remove('append-mode');
            }
        }
    }

    function saveAppendMode() {
        try {
            localStorage.setItem(APPEND_MODE_STORAGE_KEY, isAppendMode ? 'true' : 'false');
        } catch (e) {
            console.warn('[狐策面板] 无法保存追加模式状态:', e);
        }
    }

    loadActionTheme();
    loadAppendMode();

    window.toggleTheme = function(event) {
        if (event) {
            event.stopPropagation();
            event.preventDefault();
        }

        const isNight = document.body.classList.toggle('night-mode');

        if (isNight) {
            if (themeToggleBtn) themeToggleBtn.textContent = '✧';
            try {
                localStorage.setItem(ACTION_THEME_STORAGE_KEY, 'dark');
            } catch (e) {}
        } else {
            if (themeToggleBtn) themeToggleBtn.textContent = '✦';
            try {
                localStorage.setItem(ACTION_THEME_STORAGE_KEY, 'light');
            } catch (e) {}
        }
    };

    window.toggleMode = function(event) {
        if (event) {
            event.stopPropagation();
            event.preventDefault();
        }

        isSendMode = !isSendMode;
        const modeBtn = document.getElementById('modeToggleBtn');
        const appendBtn = document.getElementById('appendToggleBtn');

        if (isSendMode) {
            isAppendMode = false;
            saveAppendMode();

            if (appendBtn) {
                appendBtn.textContent = '↵';
                appendBtn.title = '追加模式：关闭';
                appendBtn.classList.remove('append-mode');
            }

            if (modeBtn) {
                modeBtn.textContent = '↗';
                modeBtn.title = '发送模式（点击切换为填充）';
                modeBtn.classList.add('send-mode');
            }

            if (statusFeedback) statusFeedback.textContent = '已切换为发送模式';
        } else {
            if (modeBtn) {
                modeBtn.textContent = '↓';
                modeBtn.title = '填充模式（点击切换为发送）';
                modeBtn.classList.remove('send-mode');
            }

            if (statusFeedback) statusFeedback.textContent = '已切换为填充模式';
        }

        clearTimeout(window._rimModeTimer);
        window._rimModeTimer = setTimeout(() => {
            if (statusFeedback) statusFeedback.textContent = '待命';
        }, 1800);
    };

    window.toggleAppendMode = function(event) {
        if (event) {
            event.stopPropagation();
            event.preventDefault();
        }

        isAppendMode = !isAppendMode;
        saveAppendMode();

        const modeBtn = document.getElementById('modeToggleBtn');
        const appendBtn = document.getElementById('appendToggleBtn');

        if (isAppendMode) {
            isSendMode = false;

            if (modeBtn) {
                modeBtn.textContent = '↓';
                modeBtn.title = '填充模式（点击切换为发送）';
                modeBtn.classList.remove('send-mode');
            }

            if (appendBtn) {
                appendBtn.textContent = '▸⏎';
                appendBtn.title = '追加模式：开启';
                appendBtn.classList.add('append-mode');
            }

            if (statusFeedback) statusFeedback.textContent = '已切换为追加模式';
        } else {
            if (appendBtn) {
                appendBtn.textContent = '↵';
                appendBtn.title = '追加模式：关闭';
                appendBtn.classList.remove('append-mode');
            }

            if (statusFeedback) statusFeedback.textContent = '已关闭追加模式，当前为填充模式';
        }

        clearTimeout(window._rimAppendModeTimer);
        window._rimAppendModeTimer = setTimeout(() => {
            if (statusFeedback) statusFeedback.textContent = '待命';
        }, 1800);
    };

    function updateContentHeight() {
        if (!content) return;
        content.style.maxHeight = isExpanded ? content.scrollHeight + 'px' : '0px';
    }

    window.toggleCollapsible = function() {
        isExpanded = !isExpanded;
        const header = collapsible.querySelector('.rim-header');

        if (isExpanded) {
            collapsible.classList.add('expanded');
            if (header) header.setAttribute('aria-expanded', 'true');

            requestAnimationFrame(() => {
                updateContentHeight();
                void content.offsetHeight;
                requestParentResize();

                setTimeout(requestParentResize, 80);
                setTimeout(requestParentResize, 240);
                setTimeout(requestParentResize, 520);
            });
        } else {
            content.style.maxHeight = content.scrollHeight + 'px';

            requestAnimationFrame(() => {
                collapsible.classList.remove('expanded');
                if (header) header.setAttribute('aria-expanded', 'false');

                content.style.maxHeight = '0px';
                requestParentResize();
                setTimeout(requestParentResize, 520);
            });
        }
    };

    function requestParentResize() {
        if (window.parent && window.parent !== window) {
            requestAnimationFrame(() => {
                window.parent.postMessage({
                    type: 'resizeIframe',
                    height: document.body.scrollHeight
                }, '*');
            });
        }
    }

    function getParentInputElement() {
        const selectors = [
            'textarea#send_textarea',
            '#send_textarea',
            'textarea[name="send_textarea"]',
            'textarea[placeholder*="发送"]',
            'textarea[placeholder*="Send"]',
            'textarea',
            'input[type="text"]'
        ];

        const docs = [];

        try { docs.push(document); } catch (e) {}
        try {
            if (window.parent && window.parent !== window && window.parent.document) {
                docs.push(window.parent.document);
            }
        } catch (e) {}
        try {
            if (window.top && window.top !== window && window.top.document) {
                docs.push(window.top.document);
            }
        } catch (e) {}

        for (const doc of docs) {
            for (const selector of selectors) {
                try {
                    const el = doc.querySelector(selector);
                    if (el && typeof el.value !== 'undefined' && !el.disabled && !el.readOnly) {
                        return el;
                    }
                } catch (e) {}
            }
        }

        return null;
    }

    function setNativeInputValue(element, value) {
        if (!element) return false;

        const win = element.ownerDocument && element.ownerDocument.defaultView
            ? element.ownerDocument.defaultView
            : window;

        const tagName = element.tagName ? element.tagName.toLowerCase() : '';
        let prototype = null;

        if (tagName === 'textarea') {
            prototype = win.HTMLTextAreaElement && win.HTMLTextAreaElement.prototype;
        } else if (tagName === 'input') {
            prototype = win.HTMLInputElement && win.HTMLInputElement.prototype;
        }

        const valueSetter = prototype
            ? Object.getOwnPropertyDescriptor(prototype, 'value')?.set
            : null;

        if (valueSetter) {
            valueSetter.call(element, value);
        } else {
            element.value = value;
        }

        element.dispatchEvent(new win.Event('input', { bubbles: true }));
        element.dispatchEvent(new win.Event('change', { bubbles: true }));

        try {
            element.focus({ preventScroll: true });
        } catch (e) {
            try { element.focus(); } catch (err) {}
        }

        try {
            const end = value.length;
            element.setSelectionRange(end, end);
        } catch (e) {}

        return true;
    }

    function appendToUserInput(text) {
        const inputEl = getParentInputElement();

        if (!inputEl) {
            console.warn('[狐策面板] 未找到用户输入框，无法追加。');
            return false;
        }

        const oldValue = inputEl.value || '';
        const separator = oldValue && !/\s$/.test(oldValue) ? '\n' : '';
        const newValue = oldValue + separator + text;

        return setNativeInputValue(inputEl, newValue);
    }

    function handleOptionClick(cardElement) {
        const plainText = cardElement.getAttribute('data-option-text') || cardElement.textContent.trim();

        cardElement.classList.add('just-used');
        setTimeout(() => {
            cardElement.classList.remove('just-used');
        }, 200);

        let modeLabel = '填充';
        let success = true;

        if (isSendMode) {
            modeLabel = '发送';
            safeTriggerSlash(`/send ${plainText}|/trigger`);
        } else if (isAppendMode) {
            modeLabel = '追加';
            success = appendToUserInput(plainText);

            if (!success) {
                if (statusFeedback) {
                    statusFeedback.textContent = '追加失败：未找到用户输入框';
                    clearTimeout(window._rimFeedbackTimer);
                    window._rimFeedbackTimer = setTimeout(() => {
                        if (statusFeedback) statusFeedback.textContent = '待命';
                    }, 2600);
                }
                return;
            }
        } else {
            modeLabel = '填充';
            safeTriggerSlash(`/setinput ${plainText}`);
        }

        if (statusFeedback) {
            statusFeedback.textContent = `✓ 已${modeLabel}: ${plainText}`;
            clearTimeout(window._rimFeedbackTimer);
            window._rimFeedbackTimer = setTimeout(() => {
                if (statusFeedback) statusFeedback.textContent = '待命';
            }, 2200);
        }
    }

    function renderFoxTip(tipText) {
        if (!foxTipArea) return;

        if (tipText && tipText.trim().length > 0) {
            foxTipArea.textContent = tipText.trim();
        } else {
            foxTipArea.textContent = '';
        }
    }

    function renderOptions(optionsData) {
        if (!actionsContainer) return;

        actionsContainer.innerHTML = '';

        if (!optionsData || optionsData.length === 0) {
            actionsContainer.innerHTML = '<div class="no-options-hint">暂无可用行动</div>';
            requestAnimationFrame(() => {
                updateContentHeight();
                requestParentResize();
            });
            return;
        }

        const fragment = document.createDocumentFragment();

        optionsData.forEach((optionData) => {
            const card = document.createElement('div');
            card.className = 'action-card';

            const htmlContent = optionData.html || optionData.text || String(optionData);
            const plainText = optionData.text || optionData;

            let wrappedHtml = htmlContent;
            const fontIdx = htmlContent.search(/<font\b/i);

            if (fontIdx > 0) {
                const before = htmlContent.substring(0, fontIdx);
                const after = htmlContent.substring(fontIdx);
                wrappedHtml = '<span style="white-space: nowrap;">' + before + '</span>' + after;
            }

            card.innerHTML = wrappedHtml;
            card.setAttribute('data-option-text', plainText);
            card.setAttribute('tabindex', '0');
            card.setAttribute('role', 'button');

            card.addEventListener('click', (e) => {
                e.stopPropagation();
                handleOptionClick(card);
            });

            card.addEventListener('keydown', (e) => {
                if (e.key === 'Enter' || e.key === ' ') {
                    e.preventDefault();
                    handleOptionClick(card);
                }
            });

            fragment.appendChild(card);
        });

        actionsContainer.appendChild(fragment);

        requestAnimationFrame(() => {
            if (isExpanded) {
                updateContentHeight();
            }
            void actionsContainer.offsetHeight;
            requestParentResize();
        });
    }

    function parseFoxSelcFormat(rawText) {
        const match = rawText.match(/<fox_selc>([\s\S]*?)<\/fox_selc>/i);
        if (!match || !match[1]) return null;

        const inner = match[1];
        const lines = inner.split('\n').filter(line => line.trim().length > 0);
        const options = [];

        lines.forEach(line => {
            let trimmed = line.trim();

            if (trimmed.length > 0) {
                const fontMatch = trimmed.match(/<font\b[^>]*>([\s\S]*?)<\/font>/i);
                const plainText = fontMatch && fontMatch[1]
                    ? fontMatch[1].replace(/<[^>]+>/g, '').trim()
                    : trimmed.replace(/<[^>]+>/g, '').trim();

                if (plainText.length > 0) {
                    options.push({
                        html: trimmed,
                        text: plainText
                    });
                }
            }
        });

        return options.length > 0 ? options : null;
    }

    function parseOptionsFormat(rawText) {
        const match = rawText.match(/<options>([\s\S]*?)<\/options>/i);
        if (!match || !match[1]) return null;

        return match[1]
            .split('|')
            .map(s => s.trim())
            .filter(s => s.length > 0)
            .map(s => ({ html: s, text: s }));
    }

    function parseFoxTipFormat(rawText) {
        const match = rawText.match(/<fox_tip>([\s\S]*?)<\/fox_tip>/i);
        if (!match || !match[1]) return null;
        return match[1].trim();
    }

    function tryExtractOptionsFromContext() {
        try {
            if (typeof getChatMessages === 'function' && typeof getCurrentMessageId === 'function') {
                const chatMessages = getChatMessages(getCurrentMessageId());

                if (chatMessages && chatMessages.length > 0) {
                    const rawMessage = chatMessages[0].message;

                    const tipText = parseFoxTipFormat(rawMessage);
                    renderFoxTip(tipText || '');

                    const foxResult = parseFoxSelcFormat(rawMessage);
                    if (foxResult && foxResult.length > 0) {
                        console.log('[环世界面板] 从 <fox_selc> 解析到选项:', foxResult.length, '个');
                        return foxResult;
                    }

                    const optResult = parseOptionsFormat(rawMessage);
                    if (optResult && optResult.length > 0) {
                        console.log('[环世界面板] 从 <options> 解析到选项:', optResult.length, '个');
                        return optResult;
                    }

                    console.log('[环世界面板] 未找到选项标签，使用默认选项');
                }
            }
        } catch (e) {
            console.warn('[环世界面板] 解析选项时出错:', e);
        }

        return null;
    }

    function init() {
        let options = tryExtractOptionsFromContext();

        if (!options || options.length === 0) {
            options = DEFAULT_OPTIONS.map(s => ({ html: s, text: s }));
        }

        renderOptions(options);

        const footerToggle = document.querySelector('.rim-footer-toggle');
        if (footerToggle) {
            footerToggle.addEventListener('click', function(e) {
                e.stopPropagation();
                window.toggleCollapsible();
            });
        }

        document.addEventListener('keydown', function(event) {
            if (event.key === 'Enter' || event.key === ' ') {
                const activeElement = document.activeElement;
                if (activeElement && activeElement.classList.contains('rim-header')) {
                    event.preventDefault();
                    window.toggleCollapsible();
                }
            }
        });

        window.addEventListener('resize', function() {
            requestParentResize();
            if (isExpanded) {
                updateContentHeight();
            }
        });

        if (window.parent && window.parent !== window && 'ResizeObserver' in window) {
            const observer = new ResizeObserver(() => {
                if (isExpanded) {
                    updateContentHeight();
                }
                requestParentResize();
            });
            observer.observe(document.body);
        }

        requestAnimationFrame(() => {
            updateContentHeight();
            requestParentResize();
        });
    }

    if (document.readyState === 'loading') {
        window.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }

    window.refreshRimOptions = function(newOptionsArray) {
        if (Array.isArray(newOptionsArray)) {
            const formatted = newOptionsArray.map(s => {
                if (typeof s === 'object' && s.html) return s;
                return { html: s, text: s };
            });

            renderOptions(formatted);

            if (statusFeedback) statusFeedback.textContent = '选项已更新';

            clearTimeout(window._rimRefreshTimer);
            window._rimRefreshTimer = setTimeout(() => {
                if (statusFeedback) statusFeedback.textContent = '待命';
            }, 1600);
        }
    };
})();
</script>
