  <script>
    (function() {
      // ===== 核心：从多种来源提取【原始输入】和其余内容 =====
      function extractRawContent() {
        var rawInput = '';
        var otherContent = '';

        // 来源1：检查页面上是否有 <fox_input> 标签
        var foxInputEl = document.querySelector('fox_input');
        if (foxInputEl) {
          var text = foxInputEl.textContent || '';
          var parsed = parseFoxInput(text);
          rawInput = parsed.rawInput;
          otherContent = parsed.otherContent;
          // 隐藏原始标签
          foxInputEl.style.display = 'none';
        }

        // 来源2：尝试通过 getChatMessages 获取最新消息
        if (!rawInput && typeof getChatMessages === 'function' && typeof getCurrentMessageId === 'function') {
          try {
            var chatMessages = getChatMessages(getCurrentMessageId());
            if (chatMessages && chatMessages.length > 0) {
              var rawMessage = chatMessages[0].message || '';
              var parsed = parseFoxInput(rawMessage);
              if (parsed.rawInput) {
                rawInput = parsed.rawInput;
                otherContent = parsed.otherContent;
              }
            }
          } catch(e) {
            console.warn('[狐令] getChatMessages 调用失败:', e);
          }
        }

        // 来源3：从 document.body.innerText 全文搜索
        if (!rawInput) {
          var bodyText = document.body.innerText || '';
          var parsed = parseFoxInput(bodyText);
          if (parsed.rawInput) {
            rawInput = parsed.rawInput;
            otherContent = parsed.otherContent;
          }
        }

        return {
          rawInput: rawInput,
          otherContent: otherContent
        };
      }

      // 解析【原始输入】区块
      function parseFoxInput(text) {
        var rawInput = '';
        var otherContent = text || '';

        // 匹配【原始输入】后面直到下一个顶级【xxx】之前的内容
        var re = /【原始输入】\s*([\s\S]*?)\s*(?=\n【)/;
        var match = (text || '').match(re);

        if (match) {
          rawInput = match[1].trim();
          otherContent = text.replace(match[0], '').trim();
        }

        return {
          rawInput: rawInput,
          otherContent: otherContent
        };
      }

      // ===== 构建组件 =====
      function createComponent(rawInput, otherContent) {
        var container = document.createElement('div');
        container.className = 'fox-collapsible';

        var displayInput = rawInput || '（暂无原始输入内容）';
        var displayOther = otherContent || '（暂无其他内容）';

        // 装饰线
        var linesDiv = document.createElement('div');
        linesDiv.className = 'afx-lines';
        for (var j = 0; j < 4; j++) {
          var line = document.createElement('div');
          line.className = 'line';
          linesDiv.appendChild(line);
        }
        container.appendChild(linesDiv);

        // 光晕
        var orbDiv = document.createElement('div');
        orbDiv.className = 'afx-orb';
        container.appendChild(orbDiv);

        // 粒子层
        var ptsDiv = document.createElement('div');
        ptsDiv.className = 'afx-pts';
        ptsDiv.setAttribute('data-particle-layer', '');
        container.appendChild(ptsDiv);

        // 头部
        var header = document.createElement('div');
        header.className = 'fox-header';
        header.setAttribute('tabindex', '0');
        header.setAttribute('role', 'button');
        header.setAttribute('aria-expanded', 'false');

        var titleDiv = document.createElement('div');
        titleDiv.className = 'fox-title';
        var titleSpan = document.createElement('span');
        titleSpan.className = 'fox-title-text';
        titleSpan.textContent = '🦊 狐令~';
        titleDiv.appendChild(titleSpan);
        header.appendChild(titleDiv);

        var actionsDiv = document.createElement('div');
        actionsDiv.className = 'header-actions';

        var themeBtn = document.createElement('button');
        themeBtn.className = 'theme-toggle-btn';
        themeBtn.setAttribute('title', '切换日夜模式');
        themeBtn.setAttribute('aria-label', '切换日夜模式');
        themeBtn.textContent = '🦊';
        actionsDiv.appendChild(themeBtn);

        var arrowDiv = document.createElement('div');
        arrowDiv.className = 'arrow-indicator';
        arrowDiv.innerHTML = '<svg viewBox="0 0 24 24"><polyline points="6 9 12 15 18 9"/></svg>';
        actionsDiv.appendChild(arrowDiv);

        header.appendChild(actionsDiv);
        container.appendChild(header);

        // 预览区
        var preview = document.createElement('div');
        preview.className = 'fox-preview';

        var label = document.createElement('div');
        label.className = 'fox-preview-label';
        label.textContent = '📝 原始输入';
        preview.appendChild(label);

        var previewContent = document.createElement('div');
        previewContent.className = 'fox-preview-content';
        previewContent.textContent = displayInput;
        preview.appendChild(previewContent);

        container.appendChild(preview);

        // 折叠区
        var content = document.createElement('div');
        content.className = 'fox-content';

        var inner = document.createElement('div');
        inner.className = 'fox-content-inner';
        inner.textContent = displayOther;
        content.appendChild(inner);

        var footer = document.createElement('div');
        footer.className = 'fox-footer-toggle';
        footer.textContent = '点我展开完整内容 ο(=•ω＜=)ρ⌒☆';
        content.appendChild(footer);

        container.appendChild(content);

        return container;
      }

      // ===== 事件绑定 =====
      function bindEvents(container) {
        var header = container.querySelector('.fox-header');
        var contentEl = container.querySelector('.fox-content');
        var footer = container.querySelector('.fox-footer-toggle');
        var themeBtn = container.querySelector('.theme-toggle-btn');
        var particleLayer = container.querySelector('[data-particle-layer]');

        var isOpen = false;

        function getStoredTheme() {
          try { return localStorage.getItem('fox-theme') || 'light'; } catch(e) { return 'light'; }
        }
        function saveTheme(theme) {
          try { localStorage.setItem('fox-theme', theme); } catch(e) {}
        }

        if (getStoredTheme() === 'dark') {
          document.body.classList.add('night-mode');
          if (themeBtn) themeBtn.textContent = '🐾';
        }

        function toggleOpen() {
          if (isOpen) {
            container.classList.remove('expanded');
            contentEl.style.maxHeight = '0';
            isOpen = false;
            header.setAttribute('aria-expanded', 'false');
          } else {
            container.classList.add('expanded');
            contentEl.style.maxHeight = contentEl.scrollHeight + 'px';
            isOpen = true;
            header.setAttribute('aria-expanded', 'true');
          }
          updateFooterText();
        }

        function updateFooterText() {
          if (footer) {
            footer.textContent = isOpen
              ? '点我收起 ο(=•ω＜=)ρ⌒☆'
              : '点我展开完整内容 ο(=•ω＜=)ρ⌒☆';
          }
        }

        function toggleTheme(e) {
          e.stopPropagation();
          var isNight = document.body.classList.toggle('night-mode');
          if (themeBtn) themeBtn.textContent = isNight ? '🐾' : '🦊';
          saveTheme(isNight ? 'dark' : 'light');
        }

        if (header) {
          header.addEventListener('click', toggleOpen);
          header.addEventListener('keydown', function(e) {
            if (e.key === 'Enter' || e.key === ' ') {
              e.preventDefault();
              toggleOpen();
            }
          });
        }

        if (footer) {
          footer.addEventListener('click', function(e) {
            e.stopPropagation();
            toggleOpen();
          });
        }

        if (themeBtn) {
          themeBtn.addEventListener('click', toggleTheme);
        }

        // 粒子
        function spawnParticles() {
          if (!particleLayer) return;
          var mobile = window.innerWidth < 520;
          var dotCount = mobile ? 6 : 10;
          var lineCount = mobile ? 0 : 4;

          function rand(a, b) { return a + Math.random() * (b - a); }

          for (var i = 0; i < dotCount; i++) {
            var p = document.createElement('div');
            var size = rand(2, 5);
            p.className = 'ax-p gd';
            p.style.width = size + 'px';
            p.style.height = size + 'px';
            p.style.left = rand(5, 92) + '%';
            p.style.top = rand(8, 88) + '%';
            p.style.setProperty('--dur', rand(5, 10) + 's');
            p.style.setProperty('--op', rand(0.14, 0.32).toFixed(2));
            p.style.animationDelay = '-' + rand(0, 20) + 's';
            particleLayer.appendChild(p);
          }

          for (var m = 0; m < lineCount; m++) {
            var pl = document.createElement('div');
            pl.className = 'ax-p lr';
            pl.style.height = rand(34, 72) + 'px';
            pl.style.left = rand(8, 90) + '%';
            pl.style.top = rand(8, 84) + '%';
            pl.style.setProperty('--dur', rand(6, 11) + 's');
            pl.style.setProperty('--op', rand(0.12, 0.26).toFixed(2));
            pl.style.animationDelay = '-' + rand(0, 20) + 's';
            particleLayer.appendChild(pl);
          }
        }

        spawnParticles();

        window.addEventListener('resize', function() {
          if (isOpen && contentEl) {
            contentEl.style.maxHeight = contentEl.scrollHeight + 'px';
          }
        });

        contentEl.style.maxHeight = '0';
        updateFooterText();
      }

      // ===== 初始化 =====
      function init() {
        var extracted = extractRawContent();
        var container = createComponent(extracted.rawInput, extracted.otherContent);
        document.body.appendChild(container);
        bindEvents(container);
      }

      if (document.readyState === 'loading') {
        window.addEventListener('DOMContentLoaded', init);
      } else {
        init();
      }
    })();
  </script>
</body>
</html>
